func calibrationHeroBg(decision string) string {
	switch decision {
	case "persevere":
		return "bg-gradient-to-br from-success/10 via-base-100 to-base-100 border-success/15"
	case "pivot":
		return "bg-gradient-to-br from-warning/10 via-base-100 to-base-100 border-warning/15"
	case "pull_the_plug":
		return "bg-gradient-to-br from-error/10 via-base-100 to-base-100 border-error/15"
	default:
		return "bg-gradient-to-br from-base-200 via-base-100 to-base-100 border-base-content/10"
	}
}

func calibrationDecisionTextColor(decision string) string {
	switch decision {
	case "persevere":
		return "text-success"
	case "pivot":
		return "text-warning"
	case "pull_the_plug":
		return "text-error"
	default:
		return "text-base-content"
	}
}

